Basically, this:
```
        class Prefetch:
                def __init__(self, cursor, size = 10000):
                        self.cursor = cursor
                        self.currentOne = []
                        self.currentTwo = []
                        self.currentThread = None
                        self.size = size

                def records(self):
                        self.currentTwo = self.cursor.fetchmany(self.size)

                def fetch(self):
                        thread = threading.Thread(target=self.records)
                        thread.daemon = True
                        thread.start()
                        return thread
                def has(self):
                        if len(self.currentOne) == 0:
                                if len(self.currentTwo) == 0:
                                        self.fetch().join()
                                        if len(self.currentTwo) == 0:
                                                return False
                                self.currentOne = self.currentTwo
                                self.currentTwo = []
                        if len(self.currentTwo) == 0:
                                if self.currentThread == None:
                                        self.currentThread = self.fetch()
                        return True
                def pop(self):
                        return self.currentOne.pop()
```

